// VAR __val = 
//     CALCULATE( 
//         [PP.Розмір мережі (співробітник, 3м)], 
//         REMOVEFILTERS( fact_Metrics )
//     ) 

VAR __val =
DIVIDE(
		SUM('fact_Viva_Metrics'[INTERNAL_NETWORK_SIZE]),
		CALCULATE(COUNTROWS('fact_Viva_Metrics'), NOT ISBLANK('fact_Viva_Metrics'[INTERNAL_NETWORK_SIZE])))

RETURN __val
